import React, { useContext, useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import {
  Play, RefreshCw, ChevronRight, AlertTriangle, TrendingDown,
  Layers, Settings2, CheckCircle2, Loader2, XCircle,
} from 'lucide-react';
import { AppCtx } from '../App';
import {
  fetchOptimizationOverview,
  startBatchAnalysis,
  fetchAnalysisJob,
} from '../api/azure';
import PageHeader from '../components/PageHeader';
import ActionMessage from '../components/ActionMessage';
import AssetIcon from '../components/AssetIcon';
import { iconForComponent } from '../config/assetIcons';
import { formatCurrency } from '../utils/format';
import { getErrorMessage } from '../api/errors';
import useResourceSync from '../hooks/useResourceSync';

const SEV_COLORS = {
  CRITICAL: '#dc2626',
  HIGH: '#f97316',
  MEDIUM: '#f59e0b',
  LOW: '#22c55e',
  INFO: '#6366f1',
};

function JobProgress({ job, onRefresh }) {
  if (!job) return null;
  const isActive = job.status === 'queued' || job.status === 'running';

  return (
    <div className="card" style={{ marginBottom: '1.25rem' }}>
      <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <strong>Batch analysis</strong>
          <span className={`badge badge--${job.status}`} style={{ marginLeft: '0.5rem' }}>
            {job.status}
          </span>
        </div>
        {isActive && (
          <button type="button" className="btn btn--ghost btn--sm" onClick={onRefresh}>
            <RefreshCw size={14} /> Refresh
          </button>
        )}
      </div>
      <div className="card-body">
        <div className="progress-bar" style={{ marginBottom: '0.75rem' }}>
          <div
            className="progress-bar__fill"
            style={{ width: `${job.progress_pct || 0}%` }}
          />
        </div>
        <p style={{ fontSize: '0.875rem', color: 'var(--text-muted)', margin: '0 0 0.75rem' }}>
          {job.current_component
            ? `Analyzing ${job.current_component}… (${job.completed_batches}/${job.total_batches})`
            : job.status === 'completed'
              ? 'All components analyzed.'
              : job.error_message || 'Waiting to start…'}
        </p>
        {Array.isArray(job.components) && job.components.length > 0 && (
          <div className="batch-components-grid">
            {job.components.map((c) => (
              <div key={c.component} className={`batch-comp batch-comp--${c.status || 'pending'}`}>
                <span className="batch-comp__name">{c.component}</span>
                <span className="batch-comp__meta">
                  {c.status === 'completed'
                    ? `${c.findings} findings · ${formatCurrency(c.savings_usd || 0)}`
                    : c.status || 'pending'}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

function ComponentCard({ row, billingCurrency }) {
  const idlePct = row.resource_count
    ? Math.round((row.idle_or_unused_count / row.resource_count) * 100)
    : 0;

  return (
    <div className="opt-component-card card">
      <div className="opt-component-card__head">
        <AssetIcon iconKey={iconForComponent(row.component)} size={22} />
        <div>
          <h3>{row.component}</h3>
          <p>{row.resource_count} resources · {row.enabled_rules}/{row.total_rules} rules on</p>
        </div>
        {row.open_findings > 0 && (
          <span className="badge badge--warning">{row.open_findings} open</span>
        )}
      </div>

      <div className="opt-component-card__stats">
        <div>
          <span className="label">MTD cost</span>
          <strong>{formatCurrency(row.mtd_cost, { currency: billingCurrency })}</strong>
        </div>
        <div>
          <span className="label">Idle / unused</span>
          <strong className={row.idle_or_unused_count > 0 ? 'text-warning' : ''}>
            {row.idle_or_unused_count}
            {row.resource_count > 0 && <small> ({idlePct}%)</small>}
          </strong>
        </div>
        <div>
          <span className="label">Potential savings</span>
          <strong className="text-success">
            {formatCurrency(row.estimated_savings_usd, { currency: billingCurrency })}
          </strong>
        </div>
      </div>

      {row.top_findings?.length > 0 && (
        <ul className="opt-component-card__findings">
          {row.top_findings.map((f, i) => (
            <li key={`${f.rule_id}-${i}`}>
              <span
                className="sev-dot"
                style={{ background: SEV_COLORS[f.severity] || '#94a3b8' }}
                title={f.severity}
              />
              <span className="finding-text">{f.resource_name}: {f.rule_name}</span>
              <span className="finding-savings">
                {formatCurrency(f.estimated_savings_usd, { currency: billingCurrency })}
              </span>
            </li>
          ))}
        </ul>
      )}

      <div className="opt-component-card__footer">
        <Link to="/engine" className="link-subtle">
          <Settings2 size={13} /> Configure rules
        </Link>
        <span className="text-muted" style={{ fontSize: '0.8rem' }}>
          {row.analyzed_resource_count} analyzed
        </span>
      </div>
    </div>
  );
}

export default function AdminOptimization() {
  const { subscription, billingCurrency } = useContext(AppCtx);
  const queryClient = useQueryClient();
  const [profile, setProfile] = useState('default');
  const [engineVersion, setEngineVersion] = useState('extended');
  const [running, setRunning] = useState(false);
  const [msg, setMsg] = useState('');
  const [activeJobId, setActiveJobId] = useState(null);

  const invalidateAll = useCallback(() => {
    if (!subscription) return;
    queryClient.invalidateQueries({ queryKey: ['opt-overview', subscription] });
    queryClient.invalidateQueries({ queryKey: ['findings-summary', subscription] });
    queryClient.invalidateQueries({ queryKey: ['findings', subscription] });
    queryClient.invalidateQueries({ queryKey: ['runs', subscription] });
    queryClient.invalidateQueries({ queryKey: ['resource-counts', subscription] });
  }, [queryClient, subscription]);

  const { sync, syncing, message: syncMsg } = useResourceSync({
    subscription,
    analyzeAfterSync: false,
    invalidateKeys: [['opt-overview', subscription], ['resource-counts', subscription]],
  });

  const { data: overview, isLoading, isError, error, refetch } = useQuery({
    queryKey: ['opt-overview', subscription, profile],
    queryFn: () => fetchOptimizationOverview({ subscription_id: subscription, profile }),
    enabled: !!subscription,
    refetchInterval: activeJobId ? 3000 : false,
  });

  const { data: activeJob, refetch: refetchJob } = useQuery({
    queryKey: ['analysis-job', activeJobId],
    queryFn: () => fetchAnalysisJob(activeJobId),
    enabled: !!activeJobId,
    refetchInterval: (q) => {
      const st = q.state.data?.status;
      return st === 'queued' || st === 'running' ? 2000 : false;
    },
  });

  useEffect(() => {
    if (activeJob?.status === 'completed') {
      invalidateAll();
      setMsg(`Batch analysis complete — ${activeJob.components?.reduce((n, c) => n + (c.findings || 0), 0) || 0} findings.`);
      setActiveJobId(null);
    } else if (activeJob?.status === 'failed') {
      setMsg(activeJob.error_message || 'Batch analysis failed.');
      setActiveJobId(null);
    }
  }, [activeJob?.status]); // eslint-disable-line react-hooks/exhaustive-deps

  const runBatch = async () => {
    if (!subscription) return;
    setRunning(true);
    setMsg('');
    try {
      const job = await startBatchAnalysis({
        subscription_id: subscription,
        profile,
        engine_version: engineVersion,
        data_source: 'db',
      });
      setActiveJobId(job.id);
      setMsg('Batch analysis started — processing one component at a time.');
    } catch (err) {
      setMsg(getErrorMessage(err, 'Could not start batch analysis.'));
    } finally {
      setRunning(false);
    }
  };

  const totals = overview?.totals || {};
  const components = overview?.components || [];

  return (
    <div className="page admin-optimization-page">
      <PageHeader
        title="Optimization center"
        subtitle="Per-component usage, waste detection, and savings — powered by your engine rules profile."
        icon={<Layers size={22} />}
      />

      <div className="toolbar" style={{ marginBottom: '1rem', flexWrap: 'wrap', gap: '0.5rem' }}>
        <select className="select-field" value={profile} onChange={(e) => setProfile(e.target.value)}>
          <option value="default">Profile: default</option>
        </select>
        <select className="select-field" value={engineVersion} onChange={(e) => setEngineVersion(e.target.value)}>
          <option value="extended">Extended engine</option>
          <option value="standard">Standard engine</option>
        </select>
        <button type="button" className="btn btn--primary" disabled={!subscription || running || !!activeJobId} onClick={runBatch}>
          {running || activeJobId ? <Loader2 size={16} className="spin" /> : <Play size={16} />}
          Run batch analysis
        </button>
        <button type="button" className="btn btn--secondary" disabled={!subscription || syncing} onClick={sync}>
          <RefreshCw size={16} className={syncing ? 'spin' : ''} />
          Sync inventory
        </button>
        <Link to="/engine" className="btn btn--ghost">
          <Settings2 size={16} /> Engine rules
        </Link>
        <Link to="/findings" className="btn btn--ghost">
          View findings <ChevronRight size={14} />
        </Link>
      </div>

      <ActionMessage message={msg || syncMsg} />

      {(activeJobId || activeJob) && (
        <JobProgress job={activeJob} onRefresh={refetchJob} />
      )}

      {!subscription && (
        <div className="empty-state">Select a subscription to view optimization coverage.</div>
      )}

      {subscription && isLoading && <div className="loading-state">Loading optimization overview…</div>}
      {subscription && isError && (
        <div className="error-state" role="alert">{getErrorMessage(error, 'Could not load overview.')}</div>
      )}

      {subscription && overview && (
        <>
          <div className="kpi-row" style={{ marginBottom: '1.25rem' }}>
            <div className="kpi-card">
              <span className="kpi-label">Resources</span>
              <strong>{totals.resource_count?.toLocaleString() || 0}</strong>
            </div>
            <div className="kpi-card">
              <span className="kpi-label">Idle / unused</span>
              <strong className="text-warning">{totals.idle_count?.toLocaleString() || 0}</strong>
            </div>
            <div className="kpi-card">
              <span className="kpi-label">Open findings</span>
              <strong>{totals.open_findings?.toLocaleString() || 0}</strong>
            </div>
            <div className="kpi-card">
              <span className="kpi-label">Potential savings (MTD)</span>
              <strong className="text-success">
                {formatCurrency(totals.estimated_savings_usd, { currency: billingCurrency })}
              </strong>
            </div>
            <div className="kpi-card">
              <span className="kpi-label">Rules enabled</span>
              <strong>{totals.enabled_rules}/{totals.total_rules}</strong>
            </div>
          </div>

          {overview.last_analyzed_at && (
            <p className="text-muted" style={{ fontSize: '0.85rem', marginBottom: '1rem' }}>
              Last analyzed {new Date(overview.last_analyzed_at).toLocaleString()}
            </p>
          )}

          <div className="opt-components-grid">
            {components.map((row) => (
              <ComponentCard key={row.component} row={row} billingCurrency={billingCurrency} />
            ))}
          </div>
        </>
      )}

      <style>{`
        .admin-optimization-page .progress-bar {
          height: 8px;
          background: var(--surface-2, #1e293b);
          border-radius: 999px;
          overflow: hidden;
        }
        .admin-optimization-page .progress-bar__fill {
          height: 100%;
          background: linear-gradient(90deg, #2563eb, #22c55e);
          transition: width 0.4s ease;
        }
        .batch-components-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
          gap: 0.5rem;
        }
        .batch-comp {
          padding: 0.5rem 0.65rem;
          border-radius: 8px;
          background: var(--surface-2, #0f172a);
          font-size: 0.8rem;
        }
        .batch-comp--completed { border-left: 3px solid #22c55e; }
        .batch-comp--pending { opacity: 0.6; }
        .batch-comp__name { display: block; font-weight: 600; }
        .batch-comp__meta { color: var(--text-muted); }
        .opt-components-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
          gap: 1rem;
        }
        .opt-component-card__head {
          display: flex;
          gap: 0.75rem;
          align-items: flex-start;
          margin-bottom: 1rem;
        }
        .opt-component-card__head h3 {
          margin: 0;
          font-size: 1rem;
        }
        .opt-component-card__head p {
          margin: 0.15rem 0 0;
          font-size: 0.8rem;
          color: var(--text-muted);
        }
        .opt-component-card__stats {
          display: grid;
          grid-template-columns: repeat(3, 1fr);
          gap: 0.75rem;
          margin-bottom: 0.75rem;
        }
        .opt-component-card__stats .label {
          display: block;
          font-size: 0.7rem;
          color: var(--text-muted);
          text-transform: uppercase;
          letter-spacing: 0.03em;
        }
        .opt-component-card__findings {
          list-style: none;
          margin: 0 0 0.75rem;
          padding: 0;
          font-size: 0.8rem;
        }
        .opt-component-card__findings li {
          display: flex;
          align-items: center;
          gap: 0.4rem;
          padding: 0.25rem 0;
        }
        .sev-dot {
          width: 8px;
          height: 8px;
          border-radius: 50%;
          flex-shrink: 0;
        }
        .finding-text { flex: 1; min-width: 0; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
        .finding-savings { color: var(--success, #22c55e); white-space: nowrap; }
        .opt-component-card__footer {
          display: flex;
          justify-content: space-between;
          align-items: center;
          border-top: 1px solid var(--border, #334155);
          padding-top: 0.65rem;
          margin-top: 0.25rem;
        }
        .text-warning { color: #f59e0b; }
        .text-success { color: #22c55e; }
      `}</style>
    </div>
  );
}
